def write_placeholders(slug, data):
    os.makedirs(os.path.join(DIR, '_placeholders'), exist_ok=True)
    lines = [f'@@@{k}@@@\n{v}\n' for k, v in data.items()]
    open(os.path.join(DIR, '_placeholders', f'{slug}.txt'), 'w', encoding='utf-8').write('\n'.join(lines))
    print(f'wrote {slug}.txt ({len(data)} segments)')

write_placeholders('5', LP5)
write_placeholders('6', LP6)
write_placeholders('7', LP7)
write_placeholders('8', LP8)
